class UnionFind {
    int[] parent;
    int[] size;
    int n;

    public UnionFind(int n) {
        this.n = n;
        parent = new int[n];
        size = new int[n];
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
            size[i] = 1;
        }
    }

    public int findset(int x) {
        return parent[x] == x ? x : (parent[x] = findset(parent[x]));
    }

    public void unite(int x, int y) {
        x = findset(x);
        y = findset(y);
        if (x == y) {
            return;
        }
        if (size[x] < size[y]) {
            int temp = x;
            x = y;
            y = temp;
        }
        parent[y] = x;
        size[x] += size[y];
    }

    public boolean connected(int x, int y) {
        x = findset(x);
        y = findset(y);
        return x == y;
    }
}
```

```Python [sol1-Python3]
class UnionFind:
    def __init__(self, n: int):
        self.n = n
        self.parent = list(range(n))
        self.size = [1] * n

    def findset(self, x: int) -> int:
        if self.parent[x] == x:
            return x
        self.parent[x] = self.findset(self.parent[x])
        return self.parent[x]

    def unite(self, x: int, y: int):
        x = self.findset(x)
        y = self.findset(y)
        if x == y:
            return
        if self.size[x] < self.size[y]:
            x, y = y, x
        self.parent[y] = x
        self.size[x] += self.size[y]

    def connected(self, x: int, y: int) -> bool:
        x = self.findset(x)
        y = self.findset(y)
        return x == y

class Solution:
    def areConnected(self, n: int, threshold: int, queries: List[List[int]]) -> List[bool]:
        uf = UnionFind(n + 1)
        for z in range(threshold + 1, n):
            for q in range(z * 2, n + 1, z):
                uf.unite(q - z, q)

        ans = list()
        for x, y in queries:
            ans.append(uf.connected(x, y))
        return ans
```

**复杂度分析**

- 时间复杂度：$O\big((n \log n + q) \cdot \alpha(n)\big)$，其中 $q$ 是数组 $\textit{queries}$ 的长度。

- 空间复杂度：$O(n)$，即为并查集需要使用的空间。

#### 方法二：并查集 + 枚举公因数优化

在方法一的基础上，我们可以继续进行一些优化。如果读者对算法竞赛有一定的了解，可以发现方法一中的预处理部分很像一个「质数筛」。方法一中的质数筛本身（不包括并查集的操作）的时间复杂度是 $O(n \log n)$ 的，我们可以将其替换成 $O(n \log \log n)$ 的[埃氏筛法](https://baike.baidu.com/item/%E5%9F%83%E6%8B%89%E6%89%98%E6%96%AF%E7%89%B9%E5%B0%BC%E7%AD%9B%E6%B3%95)。

读者如果对埃氏筛法有兴趣，可以自行通过上面给出的链接以及互联网上的资料进行学习。这里不会给出埃氏筛法的细节，而是只说明为什么可以将方法一中的普通筛法替换成埃氏筛法。

当我们枚举公因数 $z$ 时，如果存在一个之前枚举过的公因数 $z_0$，使得 $z_0 | z$（即 $z$ 是 $z_0$ 的倍数），那么我们不必枚举 $z$，这是因为 $z, 2z, 3z, \cdots$ 在这之前已经通过 $z_0$ 添加的边，两两之间连通了。

因此我们可以使用一个数组来标记每一个数是否需要被枚举。一个数没有被标记，当且仅当这个数不是之前任意一个枚举的数的倍数。当我们枚举公因数 $z$ 时，如果这个数没有被标记，我们就将 $2z, 3z, \cdots$ 都进行标记，即这些数就不需要进行枚举了。

注意到，当 $\textit{threshold}=1$ 时，**上述做法会将所有的合数进行标记**，也就是说，我们只需要枚举所有的质数作为公因数，这也是十分符合逻辑的。

**代码**

```C++ [sol2-C++]
class UnionFind {
public:
    vector<int> parent;
    vector<int> size;
    int n;

public:
    UnionFind(int _n): n(_n), parent(_n), size(_n, 1) {
        iota(parent.begin(), parent.end(), 0);
    }

    int findset(int x) {
        return parent[x] == x ? x : parent[x] = findset(parent[x]);
    }

    void unite(int x, int y) {
        x = findset(x);
        y = findset(y);
        if (x == y) {
            return;
        }
        if (size[x] < size[y]) {
            swap(x, y);
        }
        parent[y] = x;
        size[x] += size[y];
    }

    bool connected(int x, int y) {
        x = findset(x);
        y = findset(y);
        return x == y;
    }
};

class Solution {
public:
    vector<bool> areConnected(int n, int threshold, vector<vector<int>>& queries) {
        UnionFind uf(n + 1);
        vector<int> isPrime(n + 1, 1);
        for (int z = threshold + 1; z <= n; ++z) {
            if (isPrime[z]) {
                for (int p = z, q = z * 2; q <= n; p += z, q += z) {
                    uf.unite(p, q);
                    isPrime[q] = 0;
                }
            }
        }

        vector<bool> ans;
        for (const auto& q: queries) {
            int x = q[0];
            int y = q[1];
            ans.push_back(uf.connected(x, y));
        }
        return ans;
    }
};
```

